function getQuestions(category, difficulty, count = 20) {
  let pool = questions.filter(q => q.category === category && q.difficulty === difficulty)

  // If not enough questions for the specific category+difficulty, supplement from same category
  if (pool.length < count) {
    const extra = questions.filter(q => q.category === category && q.difficulty !== difficulty)
    pool = [...pool, ...extra]
  }

  // If still not enough, supplement from same difficulty
  if (pool.length < count) {
    const extra = questions.filter(q => q.difficulty === difficulty && q.category !== category)
    pool = [...pool, ...extra]
  }

  // Shuffle and pick
  const shuffled = pool.sort(() => Math.random() - 0.5)
  return shuffled.slice(0, count).map((q, idx) => ({
    ...q,
    questionNumber: idx + 1,
  }))
}

module.exports = { questions, categories, difficulties, badges, getQuestions }
